export type CaptureAutoSave = (
  deps: CaptureDeps,
) => (
  state: EditingState,
  trigger: "idle" | "blur",
) => Promise<Result<NoteFileSaved, SaveError>>;

export type PrepareSaveRequest = (
  deps: CaptureDeps,
) => (
  input: DirtyEditingSession,
) => Result<
  { kind: "validated"; request: ValidatedSaveRequest }
  | { kind: "empty-discarded"; event: EmptyNoteDiscarded },
  SaveError
>;

export type CaptureDeps = {
  readonly clockNow: ClockNow;
  readonly allocateNoteId: AllocateNoteId;
  readonly clipboardWrite: ClipboardWrite;
  readonly publish: EventBusPublish;
};

export type EmitSaveAndTransition = (
  deps: CaptureDeps,
) => (
  request: ValidatedSaveRequest,
  state: EditingState,
) => SavingState;

/** Serialize Frontmatter to YAML string.
 *  Pure function — no I/O. Used in Step 2 (serializeNote).
 *  Source: workflows.md §依存（ポート）一覧. */
type FrontmatterSerializerToYaml = (fm: Frontmatter) => string;
